INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('d33505b8685c0aa9', 'CO', '["state"]', 'ballot_access', 'Does Colorado still allow major party candidates to access the ballot via party assembly?', '["Can a candidate qualify for the Colorado primary without petitions?","SB23-101 status on party assembly ballot access","Assembly vs. petition pathway for Colorado major parties"]', 'Yes. While SB23-101 was proposed to reform ballot access, both the party assembly and petition pathways remain operative for 2026. Under CRS 1-4-102 and 1-4-601, a major party candidate qualifies for the primary ballot by receiving at least 30% of the votes at their party''s state assembly. Candidates may also choose to qualify by petition, or pursue both simultaneously (the ''dual track'' method).', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'Colorado Secretary of State - Candidate List and Rules', '2026-04-21', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('548da8c49e46b5c7', 'CO', '["state","federal"]', 'voter_interaction', 'Can unaffiliated voters participate in the Colorado primary election?', '["Colorado semi-closed primary rules for independents","CRS 1-7-201 unaffiliated primary voting","Do I have to join a party to vote in the CO primary?"]', 'Yes. Per CRS 1-7-201, unaffiliated voters in Colorado may vote in a major party''s primary without affiliating with that party. They receive a packet containing both Democratic and Republican ballots but may only return one. If both are returned, neither will count.', 'https://www.coloradosos.gov/pubs/elections/FAQs/unaffiliatedVoters.html', 'Colorado SOS - Unaffiliated Voter FAQ', '2026-04-21', 'static', 'statute_citation', 'Unaffiliated voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('1b7da0073501526e', 'CO', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run as a joint ticket in the Colorado primary?', '["When is the Lt. Gov candidate selected in Colorado?","Joint ticket rules for Colorado Governor primary","Does the Governor pick a running mate before or after the primary?"]', 'In the primary, candidates for Governor and Lieutenant Governor run separately. Per CRS 1-4-502(2), the gubernatorial nominee of each major party selects their running mate within seven days after the primary election results are certified. They then appear as a joint ticket in the general election under Article IV, Section 3 of the Colorado Constitution.', 'https://law.justia.com/constitution/colorado/cnart4.html', 'Colorado Constitution Article IV, Section 3', '2026-04-21', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('7b50915c2a2bfd19', 'CO', '["state"]', 'candidate_eligibility', 'Which statewide executive offices are ''open'' seats in the 2026 election?', '["Open statewide seats 2026 Colorado","Who is term-limited in Colorado statewide offices 2026?","Candidates for Governor, AG, SOS, and Treasurer in 2026"]', 'All four major statewide executive offices are effectively open in 2026. Governor Jared Polis (D) and State Treasurer Dave Young (D) are term-limited. Attorney General Phil Weiser (D) is vacating his seat to run for Governor, and Secretary of State Jena Griswold (D) is vacating her seat to run for Attorney General.', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'Colorado SOS - 2026 Official Primary Candidate List', '2026-04-21', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('f2ef5d1de6602271', 'CO', '["federal"]', 'election_dates', 'Which U.S. Senate seats are on the 2026 ballot in Colorado?', '["Is John Hickenlooper up for re-election in 2026?","When is Michael Bennet''s next election?","Colorado US Senate cycle 2026"]', 'Only the Class 2 seat held by Senator John Hickenlooper (D) is up for election in 2026. Senator Michael Bennet (Class 3) was re-elected in 2022 and is not on the ballot for his Senate seat until 2028 (though he is a candidate for Governor in 2026).', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'Colorado SOS - Elections Division', '2026-04-21', 'per_cycle', 'official_source_direct', 'Federal candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('d89f252ea8d4a23e', 'CO', '["state","federal","county"]', 'election_dates', 'What are the primary and general election dates for Colorado in 2026?', '["Colorado primary date 2026","Election day 2026 Colorado","When is the next state election in Colorado?"]', 'The Colorado primary election is June 30, 2026. The general election is November 3, 2026. Per CRS 1-4-101, the primary is held on the last Tuesday in June of even-numbered years.', 'https://www.coloradosos.gov/pubs/elections/electionCalendar.html', 'Colorado SOS - Election Calendar', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('03b8215765d3e3d3', 'CO', '["state","federal","county"]', 'filing_requirements', 'What are the registration deadlines for major party and independent candidates in 2026?', '["Colorado candidate filing deadlines 2026","Last day to file for office Colorado","Independent candidate deadline Colorado 2026"]', 'For major party candidates, the deadline to file for the primary was March 18, 2026. Independent (unaffiliated) candidates for the general election must file their petitions by July 9, 2026, at 3:00 PM. Write-in candidates for the general election must file an affidavit of intent by July 16, 2026.', 'https://www.coloradosos.gov/pubs/elections/Candidates/filingForms.html', 'Colorado SOS - Candidate Filing', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c1e3d6876625509f', 'CO', '["state","federal","county","municipal"]', 'filing_requirements', 'When must a candidate file their candidate affidavit in the TRACER system?', '["TRACER registration deadline Colorado","How to register a campaign committee in Colorado","CF-1 affidavit trigger Colorado"]', 'Under CRS 1-45-108(3), all candidates must file a candidate affidavit (Form CF-1) electronically via TRACER within 10 days of becoming a candidate. ''Becoming a candidate'' occurs once you publicly announce or receive/spend money to support your candidacy.', 'https://www.tracer.sos.colorado.gov/PublicSite/Homepage.aspx', 'Colorado SOS - TRACER System', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('a2de85a11049dbc6', 'CO', '["state","federal","county","municipal"]', 'filing_requirements', 'Where do I file my nomination paperwork in Colorado?', '["Who is the designated election official for state candidates in CO?","SOS vs. County Clerk filing Colorado","Filing officer for Colorado House and Senate"]', 'Candidates for federal and state offices (including Governor, AG, SOS, Treasurer, and multicounty legislative districts) file with the Secretary of State. Candidates for county offices file with their local County Clerk and Recorder. Municipal candidates file with their Municipal Clerk, and school board candidates file with the school district''s Designated Election Official (DEO).', 'https://www.coloradosos.gov/pubs/elections/FAQs/Candidate.html', 'Colorado SOS - Candidate FAQ', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('34727ab08261c173', 'CO', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Colorado?', '["Age and residency for Colorado Governor","Colorado Constitution Article IV Section 4 Governor qualifications","Who is eligible to be Governor of Colorado?"]', 'Under Article IV, Section 4 of the Colorado Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States, and a resident of Colorado for at least two years immediately preceding the election.', 'https://law.justia.com/constitution/colorado/cnart4.html', 'Colorado Constitution Article IV, Section 4', '2026-04-21', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('51b347a5b2410d1e', 'CO', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for the Colorado General Assembly?', '["Qualifications for Colorado State House and Senate","Residency requirements for Colorado legislators","How old to be a Colorado State Senator?"]', 'Per Article V, Section 4 of the Colorado Constitution, a candidate for the General Assembly must be at least 25 years old, a citizen of the United States, and have resided in their district for at least 12 months immediately preceding the election.', 'https://law.justia.com/constitution/colorado/cnart5.html', 'Colorado Constitution Article V, Section 4', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('9c4820f1a452d368', 'CO', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Colorado?', '["US Senate residency requirements Colorado","Age to run for Congress in Colorado","Federal constitutional requirements for CO candidates"]', 'Federal candidates must meet U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected. Colorado does not require House candidates to live in the district they represent, though it is standard practice.', 'https://www.coloradosos.gov/pubs/elections/Candidates/filingForms.html', 'Colorado SOS - Federal Candidate Qualifications', '2026-04-21', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('9e4eda79f029671d', 'CO', '["state"]', 'candidate_eligibility', 'What are the term limits for the Colorado General Assembly?', '["Colorado legislative term limit formula","Can a term-limited Colorado representative run for Senate?","Consecutive vs. lifetime term limits Colorado"]', 'Colorado limits state legislators to 8 consecutive years in a single chamber. Per Article V, Section 3 of the CO Constitution, Representatives may serve four consecutive 2-year terms, and Senators may serve two consecutive 4-year terms. The clock resets if a member is out of office for one full term (4 years). Members may jump chambers (House to Senate or vice versa) to serve a fresh 8-year block.', 'https://leg.colorado.gov/agencies/legislative-council-staff/term-limits', 'Colorado Constitution Article V, Section 3', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('4676d44ce5c4666a', 'CO', '["state"]', 'candidate_eligibility', 'Is State Treasurer Dave Young term-limited in 2026?', '["Dave Young 2026 re-election eligibility","Statewide executive term limits Colorado","How many terms can a CO Treasurer serve?"]', 'Yes. Per Article IV, Section 1 of the Colorado Constitution, statewide executive officers (Governor, SOS, AG, Treasurer) are limited to two consecutive four-year terms. Dave Young was first elected in 2018 and re-elected in 2022, making him ineligible for the 2026 ballot.', 'https://law.justia.com/constitution/colorado/cnart4.html', 'Colorado Constitution Article IV, Section 1', '2026-04-21', 'per_cycle', 'statute_citation', 'Statewide candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('f6d1f4da767e437d', 'CO', '["state"]', 'election_dates', 'Which Colorado State Senate districts are on the 2026 ballot?', '["Staggered Senate terms Colorado 2026","Is my Senate district up for election in 2026?","List of Colorado Senate seats up in 2026"]', 'In 2026, roughly half of the 35 Senate seats are up for election. These are the odd-numbered districts (1, 3, 5, etc.) plus any vacancies in even-numbered districts. Senators in even-numbered districts were last elected in 2024 and are next up in 2028.', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'Colorado SOS - Senate Election Cycle', '2026-04-21', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c031d60bdf63ead3', 'CO', '["state"]', 'election_dates', 'Are all Colorado House of Representatives seats up for election in 2026?', '["Colorado House term length","Is the whole CO House on the ballot in 2026?","House seat cycles Colorado"]', 'Yes. All 65 members of the Colorado House of Representatives serve 2-year terms and are elected every even-numbered year, including 2026.', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'Colorado SOS - Legislative Cycles', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('0c911ceed98cf36f', 'CO', '["judicial"]', 'election_dates', 'How do judicial retention elections work in Colorado?', '["Appellate judge retention ballot Colorado","Can a Colorado judge be opposed by a candidate?","Yes/No judicial votes Colorado 2026"]', 'Colorado uses a merit-selection system rather than contested elections for judges. At the end of their term (varying from 4 to 10 years depending on court level), judges appear on the ballot for a non-partisan ''Yes/No'' retention vote. They are not opposed by a candidate. If a majority votes ''No'', a vacancy is declared and filled by gubernatorial appointment.', 'https://coloradojudicialinstitute.org/who-we-are/about-us/frequent-questions.html', 'Colorado Judicial Institute - Retention FAQ', '2026-04-21', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('56b063c7b3f5131d', 'CO', '["state"]', 'ballot_access', 'How are vacancies in the Colorado state legislature filled?', '["Special election for Colorado legislature","Legislative vacancy committee Colorado","Who picks a replacement for a CO legislator who resigns?"]', 'Vacancies in the Colorado General Assembly are filled by a vacancy committee of the political party that formerly held the seat. Per CRS 1-12-203, there are no special elections for these vacancies; the committee selects a replacement within 30 days, and the Governor formally appoints them.', 'https://law.justia.com/constitution/colorado/cnart5.html', 'Colorado Constitution Article V, Section 2', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('2f6dd49dc0fae9b5', 'CO', '["federal"]', 'ballot_access', 'How is a vacancy in a Colorado U.S. Senate seat filled?', '["Governor appointment US Senate Colorado","Special election for US Senate Colorado","Colorado rule for replacing Hickenlooper or Bennet"]', 'Per CRS 1-12-201, if a U.S. Senate vacancy occurs, the Governor appoints a temporary replacement. The appointee serves until the next general election. At that election, a successor is elected to fill the remainder of the original 6-year term.', 'https://www.coloradosos.gov/pubs/elections/Candidates/filingForms.html', 'CRS 1-12-201', '2026-04-21', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('58189ac16f14df81', 'CO', '["state","federal","county"]', 'voter_interaction', 'What is the deadline to change party affiliation before a primary in Colorado?', '["Switching parties for primary Colorado deadline","Can I affiliate on election day in Colorado?","Colorado primary affiliation cutoff"]', 'Registered party members who wish to switch to a different party must do so no later than 22 days before the primary. Unaffiliated voters, however, can remain unaffiliated and choose a party ballot on election day, or affiliate with a party as late as election day itself.', 'https://www.coloradosos.gov/pubs/elections/FAQs/unaffiliatedVoters.html', 'Colorado SOS - Affiliation Rules', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('3898123b72041dbb', 'CO', '["state","county","municipal"]', 'filing_requirements', 'How are nicknames or middle names handled on the official Colorado ballot?', '["Name on ballot rules Colorado","Can I use a nickname on the Colorado ballot?","CRS 1-4-101 candidate name format"]', 'Per CRS 1-4-101(3), a candidate''s name on the ballot must be their last name and at least one given name (or initial). Nicknames are allowed if they do not imply a professional title (like ''Doc'' or ''Judge'') and are used in good faith. Candidates must indicate their name preference on their Candidate Acceptance form.', 'https://www.coloradosos.gov/pubs/elections/FAQs/Candidate.html', 'CRS 1-4-101', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('e625f4e66af4cc3e', 'CO', '["state","federal","county"]', 'ballot_access', 'How many signatures are required for a major party candidate petition in Colorado?', '["Colorado petition signature requirements by office","Gubernatorial petition threshold Colorado","How many signatures for Colorado House or Senate?"]', 'Petition requirements vary by office. Statewide candidates (Governor/Senate) require 1,500 signatures per congressional district (totaling 12,000 for all 8 districts). State Senate candidates require 1,000 signatures or 30% of the last vote cast for the office, whichever is less. State House candidates require 500 signatures or 30% of the last vote cast, whichever is less.', 'https://www.coloradosos.gov/pubs/elections/Candidates/filingForms.html', 'Colorado SOS - Petition Signature Requirements', '2026-04-21', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('38d47970f55ffeea', 'CO', '["municipal"]', 'filing_requirements', 'What is the filing process for municipal candidates in home rule vs. statutory cities?', '["Colorado municipal candidate filing","Running for city council in Colorado","Statutory city candidate rules Colorado"]', 'In statutory cities and towns, filing is governed by CRS Title 31. Candidates must file a nomination petition with the municipal clerk no later than 71 days before the election. In ''home rule'' cities, the city charter dictates the process, which may include different deadlines or signature requirements.', 'https://www.coloradosos.gov/pubs/elections/FAQs/Candidate.html', 'CRS Title 31 / Municipal Charters', '2026-04-21', 'static', 'statute_citation', 'Municipal candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('9bdefdb07cd5ef59', 'CO', '["state","county","municipal"]', 'ballot_access', 'What is the ''30% rule'' for party assemblies in Colorado?', '["Colorado assembly ballot access threshold","Designation at party assembly Colorado","Winning the assembly in Colorado"]', 'Under CRS 1-4-601, a candidate who receives at least 30% of the votes cast by the delegates at a party assembly is designated for the primary ballot. If no candidate reaches 30%, a second ballot is held. If only one candidate receives 30% or more, they are the sole assembly-designated candidate.', 'https://www.coloradosos.gov/pubs/elections/vote/primaryCandidates.html', 'CRS 1-4-601', '2026-04-21', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('e3e70791ba4adf17', 'CO', '["state"]', 'candidate_eligibility', 'When does the Colorado Voting Rights Act (SB25-001) take effect?', '["Colorado Voting Rights Act 2026 status","SB25-001 implementation date","New voting laws Colorado 2026"]', 'The Colorado Voting Rights Act (SB25-001) applies to all elections and election-related activities occurring on or after January 1, 2026. It establishes statewide protections against voter suppression and vote dilution, expanding the state''s ability to monitor local election administration.', 'https://leg.colorado.gov/bills/sb25-001', 'Colorado General Assembly - SB25-001', '2026-04-21', 'static', 'statute_citation', 'All candidates and voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('e581bb1d6ff62ec6', 'CO', '["state"]', 'finance_ethics', 'What are the individual contribution limits for Colorado candidates in the 2025-2026 cycle?', '["How much can an individual donate to a CO Governor candidate?","Current campaign contribution limits for state legislature in Colorado","Colorado individual donation caps 2026 election"]', 'For the 2025-2026 cycle, individual contribution limits are $725 per election for statewide offices (Governor, AG, SOS, Treasurer) and $225 per election for state legislative offices (Senate, House). Because the primary and general elections are considered separate cycles, a donor may contribute the limit twice in one year if the candidate contests both. These figures are inflation-adjusted biennially under Article XXVIII, Section 3 of the Colorado Constitution.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/limits/candidate.html', 'Colorado Secretary of State - Contribution Acceptance Limits', '2026-05-14', 'per_cycle', 'official_source_direct', 'All state candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c4739d722f513adc', 'CO', '["state"]', 'finance_ethics', 'What is a ''small donor committee'' in Colorado and what are its contribution limits?', '["Enhanced contribution limits for small donor committees Colorado","Definition of a CO small donor committee","How much can a small donor committee give to a CO candidate?"]', 'Under Article XXVIII, Section 2(14) of the Colorado Constitution, a ''small donor committee'' is a political committee that accepts contributions only from natural persons (humans) in amounts of $50 or less per year. In exchange for this restriction, they enjoy significantly higher contribution limits to candidates: $7,825 per election for statewide offices and $3,100 per election for legislative offices in the 2025-2026 cycle.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/limits/candidate.html', 'Colorado Constitution Article XXVIII, Section 2(14)', '2026-05-14', 'per_cycle', 'statute_citation', 'All state candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('972a914420638673', 'CO', '["state","county","municipal"]', 'finance_ethics', 'Are corporations or labor unions allowed to contribute directly to candidate committees in Colorado?', '["Corporate contribution ban Colorado","Can a union donate to my campaign in Colorado?","Prohibition on corporate and labor treasury funds CO candidates"]', 'No. Article XXVIII, Section 3(4) of the Colorado Constitution strictly prohibits corporations and labor organizations from making direct contributions to candidate committees or political parties. They may, however, establish and pay for the administrative costs of a separate political committee or independent expenditure committee (IEC).', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Constitution Article XXVIII, Section 3(4)', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('b77ff32a294e01df', 'CO', '["state"]', 'finance_ethics', 'How do voluntary spending limits work for Colorado state candidates?', '["CO voluntary spending limit acceptance benefits","What happens if I accept spending limits in Colorado?","Opponent enhanced contribution limits trigger Colorado"]', 'Candidates who accept voluntary spending limits (VSL) receive specific statutory benefits. If a candidate accepts the VSL and their opponent does not, and that opponent subsequently spends or raises more than 10% of the limit, the VSL-accepting candidate''s contribution limits from individuals are doubled. Acceptance of VSL must be indicated on the candidate affidavit filed via TRACER under Article XXVIII, Section 4 of the CO Constitution.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Constitution Article XXVIII, Section 4', '2026-05-14', 'static', 'statute_citation', 'State executive and legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('88a305e83dbdc6ef', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for anonymous and minor contributions in Colorado?', '["Anonymous donation limit Colorado","Can minors donate to Colorado campaigns?","Reporting anonymous contributions CO"]', 'Anonymous contributions are prohibited in any amount over $20 per reporting period. If a candidate receives an anonymous contribution exceeding $20, the excess must be donated to a 501(c)(3) or the state treasury. Contributions from minors (under 18) are permitted but are attributed to their parents or guardians for the purpose of the individual contribution limit under Article XXVIII, Section 3.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Campaign and Political Finance Manual', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('1fc68ddd838af050', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure and itemization thresholds for donor reporting in Colorado?', '["When do I have to list a donor''s name in Colorado?","Itemization threshold campaign finance CO","Donor employer and occupation disclosure Colorado"]', 'Under CRS 1-45-108, contributions of less than $20 do not need to be itemized but must be reported in aggregate. Contributions of $20 or more must be itemized with the donor''s name and address. Contributions of $100 or more must also include the donor''s occupation and employer. These are aggregate thresholds within a reporting period.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-108', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('acf9e3c9f12db339', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is the 2026 campaign finance reporting schedule for Colorado state candidates?', '["CO campaign finance filing dates 2026","When are TRACER reports due for Colorado 2026 primary?","Colorado pre-primary and pre-general report deadlines"]', 'For the 2026 cycle, candidates follow a tiered schedule. Key dates include: Quarter 1 (April 15), Quarter 2 (July 15), and the primary-specific reports: May 4 (biweekly start), May 18, June 1, June 15, and the pre-primary report on June 26. Pre-general reports are due October 13 and October 26, 2026. Major contributions ($1,000+) received between June 25–June 29 (primary) or Oct 29–Nov 2 (general) must be reported within 24 hours.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/filingCalendars/2026.html', 'Colorado SOS - 2026 Filing Calendar', '2026-05-14', 'per_cycle', 'official_source_direct', 'State and multi-county candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('d7b2bfa4a281bab8', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer is required on Colorado campaign advertisements and mailers?', '["Colorado ''Paid for by'' requirements","Campaign ad disclaimer rules CO","Does a digital ad need a disclaimer in Colorado?"]', 'Under Article XXVIII and CRS 1-45-107.5, any communication that ''expressly advocates'' for a candidate or ballot issue must include a ''Paid for by [Committee Name]'' disclaimer. For independent expenditures, the disclaimer must also state that the communication was not authorized by any candidate. Specific font size and visibility rules apply to print (12pt), video (4 seconds), and digital ads.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-107.5', '2026-05-14', 'static', 'statute_citation', 'All candidates and PACs', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('7e37bdae2fe550e1', 'CO', '["state","county","municipal"]', 'finance_ethics', 'Are candidate committee funds prohibited from being used for personal expenses in Colorado?', '["CO personal use prohibition campaign finance","Can I use campaign money for my mortgage in Colorado?","Prohibited expenditures Colorado campaign finance"]', 'Yes. Article XXVIII, Section 2(3) and CRS 1-45-103.7 strictly prohibit the use of campaign contributions for ''personal use,'' defined as any expense that would exist irrespective of the candidate''s campaign. This includes home mortgage payments, personal clothing, and country club dues. Candidates may, however, use funds for reasonable and necessary child care expenses incurred due to campaign activities.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Article XXVIII, Section 2(3)', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('93d6da200cf16d4a', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What are the rules regarding unexpended campaign funds after an election in Colorado?', '["What can I do with leftover campaign money in Colorado?","CO surplus campaign funds rules","Donating remaining campaign funds Colorado"]', 'Unexpended funds may be used in four ways per CRS 1-45-106: (1) contributed to a political party, (2) donated to a 501(c)(3) charitable organization, (3) returned to contributors (pro-rata), or (4) retained for a future campaign for the same office. Funds may also be used for candidate expenses related to being an elected official, such as voter communication or travel, but never for personal benefit.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-106', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('6d7086185781e1f9', 'CO', '["state","county","municipal"]', 'finance_ethics', 'When does outside group activity constitute ''prohibited coordination'' in Colorado?', '["CO campaign coordination rules","When is a PAC expenditure not independent in Colorado?","Prohibition on candidate-PAC coordination CO"]', 'An expenditure is ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their agent. Under CRS 1-45-103(7), coordinated expenditures are treated as direct contributions to the candidate and are subject to the same contribution limits. Evidence of coordination includes sharing non-public strategic data or using a common consultant for media placement.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-103(7)', '2026-05-14', 'static', 'statute_citation', 'All candidates and IECs', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c2c9c7fa40af3521', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What are the late filing penalties for campaign finance reports in Colorado?', '["CO TRACER late fee","Penalty for missing a Colorado campaign finance deadline","Secretary of State fine for late filing CO"]', 'Under Article XXVIII, Section 10, the Secretary of State imposes a mandatory penalty of $50 per day for each day a required report is late. For small donor committees or political committees, this fine can be significant. Candidates can request a waiver or reduction of the fine by demonstrating ''good cause,'' such as a medical emergency or TRACER system failure.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Article XXVIII, Section 10', '2026-05-14', 'static', 'statute_citation', 'All candidates and committees', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('56b78fa3eabb9faa', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What are the restrictions on contributions from registered lobbyists to Colorado candidates?', '["CO lobbyist donation ban","Can a lobbyist give to a Colorado legislator?","Lobbyist contribution limits Colorado"]', 'Registered lobbyists are prohibited from contributing to, or soliciting contributions for, any member of the General Assembly or a candidate for the General Assembly while the legislature is in session (January through May). Outside of session, lobbyists may contribute but are subject to the standard individual contribution limits per CRS 1-45-105.5.', 'https://www.coloradosos.gov/pubs/lobby/lobbyManual.html', 'CRS 1-45-105.5', '2026-05-14', 'static', 'statute_citation', 'Legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('b20e74fcc0446968', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is an ''Independent Expenditure Committee'' (IEC) and how does it differ from a PAC?', '["CO IEC definition","Independent expenditure vs political committee Colorado","Disclosure for CO independent expenditure groups"]', 'An Independent Expenditure Committee (IEC) is a committee that makes expenditures solely for communications that expressly advocate for or against a candidate but does not coordinate with any candidate or party. Unlike political committees (PACs), IECs can accept unlimited contributions from corporations and labor unions but cannot make any contributions directly to candidates per CRS 1-45-107.5.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-107.5', '2026-05-14', 'static', 'statute_citation', 'State and local candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('b5666470a2f94c34', 'CO', '["state"]', 'candidate_eligibility', 'Are Colorado public employees restricted from participating in political activity?', '["Can a Colorado state employee run for office?","PERA employee political activity rules","On-duty political activity ban Colorado"]', 'Under the State Personnel System rules and CRS 24-50-132, state employees may participate in political activity and run for office, but they are strictly prohibited from using state resources (time, computers, office space) for campaign purposes while on duty. They must also ensure their candidacy does not create a conflict of interest with their official state duties.', 'https://spb.colorado.gov/personnel-rules', 'CRS 24-50-132', '2026-05-14', 'static', 'statute_citation', 'Candidates and public employees', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('25d80576ff921210', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is an ''electioneering communication'' and when must it be disclosed in Colorado?', '["Definition of electioneering communication Article XXVIII","Disclosure window for electioneering ads Colorado","Dollar threshold for reporting electioneering communications CO"]', 'Under Article XXVIII, Section 2(7) of the CO Constitution, an ''electioneering communication'' is any communication unambiguously referring to a candidate that is disseminated within 30 days before a primary or 60 days before a general election. Any person expending $1,000 or more per calendar year on such communications must file a disclosure report with the Secretary of State.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Constitution Article XXVIII, Section 2(7)', '2026-05-14', 'static', 'statute_citation', 'All committees and individuals', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('b2234098162cb8d2', 'CO', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Colorado?', '["Colorado in-kind contribution valuation rules","Reporting non-monetary donations Colorado campaign","Fair market value for in-kind gifts CO"]', 'Per CRS 1-45-103(1.5), in-kind contributions must be reported at their fair market value—the price the candidate would have paid for the item or service on the open market. They are subject to the same contribution limits as cash. Campaigns must report the date received, the donor''s information, and a description of the goods or services provided.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-103(1.5)', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('8ccb5097e8c6ecab', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for a candidate loaning personal funds to their own campaign in Colorado?', '["Colorado candidate personal loan limits","Can I pay myself back for a campaign loan in CO?","Reporting candidate loans in TRACER"]', 'Under Colorado law, candidates may make unlimited personal loans to their committees. Unlike third-party loans, there is no cap on candidate self-funding. However, per CRS 1-45-103.7, any loan must be documented in TRACER and can only be repaid from campaign contributions. Repayments are prohibited if they would result in the personal use of funds.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'CRS 1-45-103.7', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('6aa3c42a54396e67', 'CO', '["state","county","municipal"]', 'finance_ethics', 'Are small campaigns exempt from mandatory electronic filing in TRACER?', '["Colorado campaign finance filing exemptions","Paper filing for small Colorado campaigns","TRACER mandatory use CRS 1-45-109"]', 'No. Under CRS 1-45-109, all candidates and committees required to file with the Secretary of State must do so electronically via the TRACER system. There are no exemptions based on campaign size or total funds raised; even a campaign with $0 in activity must file ''No Activity'' reports electronically by the deadline.', 'https://tracer.sos.colorado.gov/', 'CRS 1-45-109', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('8ec0b6be90d3d169', 'CO', '["state","county","municipal"]', 'finance_ethics', 'When and how must a candidate committee be terminated in Colorado?', '["Closing a Colorado campaign committee","TRACER committee termination requirements","Final campaign finance report Colorado"]', 'A committee may terminate only when it has a zero balance and no outstanding debts. Under SOS Rule 2.2, the committee must file a final report in TRACER indicating a zero balance and checking the ''Termination'' box. This may occur after an election or at any time the committee ceases operation and disposes of all funds.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'SOS Campaign Finance Rule 2.2', '2026-05-14', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('04d3187bca024de0', 'CO', '["state"]', 'finance_ethics', 'What are the contribution limits for a standard political committee (PAC) to a Colorado candidate?', '["CO PAC donation limits to candidates 2026","Political committee vs individual contribution limit Colorado","Maximum PAC gift to state legislator CO"]', 'For the 2025-2026 cycle, standard political committees (PACs) are subject to the same contribution limits as individuals: $725 per election for statewide candidates and $225 per election for legislative candidates. This differs from ''Small Donor Committees,'' which have significantly higher limits.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/limits/candidate.html', 'Colorado Secretary of State - Contribution Limits', '2026-05-14', 'per_cycle', 'official_source_direct', 'State candidates and PACs', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('866bbfbacbf1eb47', 'CO', '["state","federal","county","municipal"]', 'finance_ethics', 'What are the restrictions on campaign contributions from foreign nationals in Colorado?', '["Can non-citizens donate to Colorado campaigns?","Foreign national contribution ban Colorado","Article XXVIII Section 3 foreign donations"]', 'Under Article XXVIII, Section 3(12) of the CO Constitution and federal law, it is unlawful for any candidate or committee to knowingly accept a contribution from any person who is not a U.S. citizen. This prohibition excludes lawful permanent residents (''Green Card'' holders) as defined by federal statute.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Constitution Article XXVIII, Section 3(12)', '2026-05-14', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('5d07020e4ca0ba90', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is the Colorado Campaign and Political Finance Manual and where is it found?', '["Official Colorado campaign finance guidebook","Latest CPF Manual update Colorado","SOS guidance for Colorado treasurers"]', 'The Colorado Campaign and Political Finance (CPF) Manual is the official regulatory guidebook published by the Secretary of State''s Elections Division. It provides comprehensive guidance on reporting, limits, and compliance. It is available on the SOS website and is typically updated annually; the current version was finalized in early 2026.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado SOS - Campaign Finance Manual', '2026-05-14', 'per_cycle', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('30951c8b2d90b9d6', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What disclosure obligations apply to candidates who are current public officials under the Ethics in Government Act?', '["Colorado Ethics in Government Act candidate requirements","Public official candidate financial disclosure CO","CRS 24-6-202 personal financial disclosure"]', 'Under the Colorado Ethics in Government Act (CRS 24-6-202), current public officials running for office must file a Personal Financial Disclosure (PFD) statement. This includes sources of income, business interests, and creditors. This is separate from campaign finance reporting and is filed with the Secretary of State within 30 days of becoming a candidate.', 'https://www.coloradosos.gov/pubs/lobby/financialDisclosure.html', 'CRS 24-6-202', '2026-05-14', 'static', 'statute_citation', 'Public official candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('4c2298e383aa114f', 'CO', '["state"]', 'finance_ethics', 'Does Colorado provide public financing for state-level political campaigns?', '["Public matching funds for Colorado Governor","State funded campaigns Colorado status","Government campaign grants Colorado"]', 'No. Colorado does not have a system of public financing or matching funds for state-level political campaigns (Governor, AG, SOS, Treasurer, or General Assembly). All candidate funding must come from private contributions within the established constitutional and statutory limits.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado SOS - Campaign Finance FAQ', '2026-05-14', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('78e02fc34c72f0b8', 'CO', '["state","county","municipal"]', 'finance_ethics', 'Does Colorado''s ban on foreign national contributions apply to lawful permanent residents (Green Card holders)?', '["Can Green Card holders donate to Colorado state campaigns?","Are lawful permanent residents considered foreign nationals in Colorado?","Article XXVIII Section 3(12) exemptions for non-citizens"]', 'No. While Article XXVIII, Section 3(12) of the Colorado Constitution bans contributions from ''foreign citizens,'' Colorado campaign finance law and the Secretary of State defer to the federal definition of a foreign national (52 U.S.C. § 30121). This federal definition explicitly exempts lawful permanent residents (Green Card holders), allowing them to legally contribute to Colorado state and local campaigns.', 'https://www.coloradosos.gov/pubs/elections/CampaignFinance/manual.html', 'Colorado Campaign and Political Finance Manual', '2026-04-21', 'static', 'official_source_direct', 'All candidates and donors', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('567ea93aaddb1a87', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Colorado''s universal mail ballot system impact campaign operations?', '["When do voters receive mail ballots in Colorado?","CRS 1-7.5-104 ballot mailing schedule","Colorado all-mail election rules"]', 'Colorado is a universal mail ballot state (CRS 1-7.5-104). Every active registered voter is automatically mailed a ballot roughly 22 days before an election. Operationally, campaigns must shift GOTV efforts earlier, as a significant portion of the electorate casts their vote weeks before Election Day.', 'https://law.justia.com/codes/colorado/2022/title-1/article-7-5/section-1-7-5-104/', 'CRS 1-7.5-104', '2026-04-21', 'static', 'statute_citation', 'All campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c5047fc0c6bfa671', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Colorado allow same-day voter registration?', '["Voter registration deadline Colorado","Can I register to vote on Election Day in CO?","Deadline to receive a mail ballot Colorado"]', 'Yes, Colorado allows eligible residents to register to vote up to and on Election Day. However, to automatically receive a ballot by mail, voters must register at least 8 days before the election. Those registering after this deadline must vote in person or request a ballot at a Voter Service and Polling Center (VSPC).', 'https://www.coloradosos.gov/pubs/elections/FAQs/VoterRegistrationFAQ.html', 'Colorado Secretary of State - Voter Registration FAQ', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('49ddcb16d21f3bff', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'What are Voter Service and Polling Centers (VSPCs) in Colorado?', '["Where do I vote in person in Colorado?","Colorado polling place rules","Do I have to vote at a specific precinct in CO?"]', 'Voter Service and Polling Centers (VSPCs) replace traditional neighborhood precincts. Registered voters can visit any VSPC within their county to vote in person, drop off a mail ballot, register to vote, or update their registration. They are staffed by bipartisan teams of election judges to ensure security and accessibility.', 'https://www.coloradosos.gov/pubs/elections/FAQs/VSPCFAQ.html', 'Colorado Secretary of State - VSPC FAQ', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('23e12ed4478d7f09', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the rules for ballot drop boxes in Colorado?', '["Are ballot drop boxes secure in Colorado?","CO drop box collection rules","Bipartisan handling of ballots Colorado"]', 'Colorado mandates 24/7 secure ballot drop boxes for all state elections. Under state law and updated security protocols, drop boxes must be monitored by video surveillance. Ballots must be collected frequently by a bipartisan team of election judges to ensure chain of custody.', 'https://www.coloradosos.gov/pubs/elections/FAQs/DropBoxFAQ.html', 'Colorado Secretary of State - Drop Box FAQ', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('a884941099597c4e', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to cure a rejected ballot signature in Colorado?', '["How to fix a ballot signature in Colorado","Colorado ballot cure process deadline","TXT2Cure system Colorado"]', 'If a ballot signature is missing or fails verification, the county clerk notifies the voter. The voter has until 8 days after Election Day (by 11:59 PM) to cure the discrepancy. This can be done using a paper form, by email, or via the state''s mobile phone cure system (TXT2Cure).', 'https://www.coloradosos.gov/pubs/elections/FAQs/SignatureCureFAQ.html', 'Colorado Secretary of State - Signature Cure FAQ', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('f0720c5a67a218ab', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Colorado?', '["How close can I campaign to a polling place in CO?","Buffer zone around drop boxes Colorado","CRS 1-13-714 electioneering rules"]', 'Colorado prohibits electioneering within 100 feet of any building in which a VSPC is located, or within 100 feet of any standalone drop box, per CRS 1-13-714. This prohibition includes displaying campaign signs, distributing literature, and soliciting votes.', 'https://law.justia.com/codes/colorado/2022/title-1/article-13/part-7/section-1-13-714/', 'CRS 1-13-714', '2026-04-21', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('4d05624c74b148e8', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'Can campaigns purchase the voter file from the state in Colorado?', '["Colorado SCORE database access","How to get the voter list in Colorado","Cost of voter registration data CO"]', 'Yes. Campaigns can purchase voter registration data from the Statewide Colorado Registration and Election (SCORE) system. The file contains registration data and voting history (whether they voted, not who they voted for) and is available for a standardized fee from the Secretary of State or individual county clerks.', 'https://www.coloradosos.gov/pubs/elections/SCORE/', 'Colorado Secretary of State - SCORE System', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('6a78906c7d36eb35', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Colorado?', '["When are military ballots due in Colorado?","UOCAVA return deadline CO","Overseas voting rules Colorado"]', 'Ballots are transmitted to UOCAVA voters 45 days before an election. Unlike domestic mail ballots which must be received by 8:00 PM on Election Day, UOCAVA ballots are counted if they are transmitted by 7:00 PM on Election Day and received by the county clerk by the close of business on the 8th day following the election.', 'https://www.coloradosos.gov/pubs/elections/UOCAVA.html', 'Colorado Secretary of State - UOCAVA Voters', '2026-04-21', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('9d3b5ef891d43ac1', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Colorado?', '["What is a provisional ballot in CO?","When do election judges issue provisional ballots?","Counting provisional votes Colorado"]', 'Provisional ballots are issued when a voter''s eligibility cannot be immediately verified at a VSPC (e.g., they do not have acceptable ID or claim to have not received a mail ballot, but the system shows a mail ballot was issued). They are kept securely separate and are only counted if the voter''s eligibility is confirmed during the post-election canvass.', 'https://www.coloradosos.gov/pubs/elections/FAQs/ProvisionalFAQ.html', 'Colorado Secretary of State - Provisional Ballot FAQ', '2026-04-21', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('94d1b040b627b40e', 'CO', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Colorado restore voting rights to individuals with felony convictions?', '["Can felons vote in Colorado?","Felony voting rights restoration CO","Voting on parole in Colorado"]', 'Yes. In Colorado, an individual convicted of a felony regains their right to vote immediately upon release from incarceration. Individuals who are on parole, probation, or who have completed their sentences are fully eligible to register and vote.', 'https://www.coloradosos.gov/pubs/elections/FAQs/VotingRightsRestoration.html', 'Colorado Secretary of State - Voting Rights Restoration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('86f7947f81da027f', 'CO', '["state","county","municipal"]', 'finance_ethics', 'What is TABOR and what does it restrict in Colorado?', '["Colorado Taxpayer''s Bill of Rights definition","Article X Section 20 of the Colorado Constitution","What does TABOR do in Colorado?"]', 'The Taxpayer''s Bill of Rights (TABOR), Article X, Section 20 of the Colorado Constitution, severely limits the amount of revenue governments can retain and spend. Crucially, it requires explicit voter approval for any new tax, tax rate increase, or creation of multi-year financial debt.', 'https://law.justia.com/constitution/colorado/cnart10.html', 'Colorado Constitution Article X, Section 20', '2026-04-21', 'static', 'statute_citation', 'All candidates and campaigns', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('4da697160541c85e', 'CO', '["state"]', 'finance_ethics', 'How is the TABOR revenue cap calculated?', '["Colorado TABOR limit formula","How fast can Colorado state revenue grow?","TABOR inflation and population growth cap"]', 'The TABOR revenue cap limits annual state revenue growth to a specific formula: it is calculated based on the prior year''s inflation (using the Denver-Aurora-Lakewood Consumer Price Index) plus the percentage change in the state''s population.', 'https://leg.colorado.gov/agencies/legislative-council-staff/tabor', 'Colorado Legislative Council Staff - TABOR', '2026-04-21', 'static', 'official_source_direct', 'State candidates and strategists', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('1b24ea3055d086cf', 'CO', '["state"]', 'finance_ethics', 'What happens if Colorado collects revenue above the TABOR cap?', '["TABOR refund mechanism Colorado","How are TABOR surpluses handled?","What is a TABOR refund check?"]', 'Any revenue collected over the TABOR cap is considered a surplus and must be refunded to taxpayers in the following fiscal year. The legislature establishes the refund mechanisms (e.g., income tax reductions, direct checks), unless the legislature refers a ballot measure to the voters and successfully obtains permission to retain the excess funds.', 'https://leg.colorado.gov/agencies/legislative-council-staff/tabor', 'Colorado Legislative Council Staff - TABOR', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('9cd1f5127e71f688', 'CO', '["county","municipal"]', 'finance_ethics', 'Does TABOR apply to local governments and what is ''De-Brucing''?', '["Does TABOR affect Colorado cities and school districts?","What does it mean to De-Bruce in Colorado?","Waiving TABOR limits locally"]', 'TABOR applies to all levels of Colorado government, including counties, municipalities, and school districts. ''De-Brucing'' is the political process where a local government asks its voters to permanently or temporarily waive the TABOR revenue cap, allowing the entity to retain and spend all collected revenues without refunding the surplus.', 'https://leg.colorado.gov/agencies/legislative-council-staff/tabor-local-governments', 'Colorado Legislative Council Staff - TABOR and Local Governments', '2026-04-21', 'static', 'official_source_direct', 'Local candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('4e47330db548ca6b', 'CO', '["state","county","municipal"]', 'finance_ethics', 'Can the Colorado legislature unilaterally raise taxes?', '["How are tax increases passed in Colorado?","TABOR voter approval requirement for taxes","Can a supermajority raise taxes in CO?"]', 'No. Under TABOR, regardless of legislative supermajorities or executive support, any policy that creates a net tax revenue increase (new tax, tax rate increase, or tax extension) must be placed on the ballot and approved by a majority of Colorado voters.', 'https://law.justia.com/constitution/colorado/cnart10.html', 'Colorado Constitution Article X, Section 20', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('44fec7d840cf746e', 'CO', '["federal","state"]', 'redistricting', 'How does Colorado handle congressional and legislative redistricting?', '["Who draws the district maps in Colorado?","Colorado Amendments Y and Z","Independent redistricting commissions CO"]', 'Following Amendments Y and Z (2018), Colorado utilizes two Independent Redistricting Commissions—one for Congress and one for the legislature. Each commission consists of 12 members (4 Democrats, 4 Republicans, 4 unaffiliated voters), entirely removing map-drawing power from the state legislature.', 'https://redistricting.colorado.gov/', 'Colorado Independent Redistricting Commissions', '2026-04-21', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('8eb02ad91b98a6aa', 'CO', '["federal","state"]', 'redistricting', 'What criteria must the Colorado independent redistricting commissions follow?', '["Colorado redistricting rules","Gerrymandering ban Colorado","How are Colorado maps drawn?"]', 'The commissions must create maps that achieve equal population, comply with the federal Voting Rights Act, preserve communities of interest and political subdivisions, remain compact, and maximize political competitiveness. Partisan gerrymandering is strictly prohibited by the state constitution.', 'https://redistricting.colorado.gov/', 'Colorado Independent Redistricting Commissions', '2026-04-21', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('7eaaebceab5a8c83', 'CO', '["federal","state"]', 'redistricting', 'Are the current Colorado redistricting maps operative for the 2026 cycle?', '["Will Colorado get new maps for 2026?","Legal challenges to Colorado districts","Status of Colorado maps 2026"]', 'Yes. The current congressional and state legislative maps were adopted by the independent commissions in 2021, approved by the Colorado Supreme Court, and remain fully operative for the 2026 election cycle without any systemic pending legal challenges.', 'https://redistricting.colorado.gov/', 'Colorado Independent Redistricting Commissions', '2026-04-21', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('f97f038174a58d04', 'CO', '["state","county","municipal"]', 'recall_rules', 'What are the signature thresholds and grounds for a recall election in Colorado?', '["How to recall a state official in Colorado","Colorado recall requirements","Do you need cause to recall a politician in CO?"]', 'Colorado allows the recall of any elected official without requiring specific grounds (like malfeasance). To trigger a state recall, proponents must gather valid signatures equal to 25% of the total votes cast at the last election for that specific office, generally within a 60-day window.', 'https://www.coloradosos.gov/pubs/elections/Recall/', 'Colorado Secretary of State - Recall Elections', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('485065b6d5e39476', 'CO', '["state"]', 'recall_rules', 'Have state legislators ever been successfully recalled in Colorado?', '["Colorado 2013 recall history","Recalled politicians Colorado","Gun control recall Colorado state senate"]', 'Yes. In 2013, two Democratic state senators (John Morse and Angela Giron) were successfully recalled over their support for gun control legislation. These were the first and only successful state legislative recalls in Colorado history, highlighting the operational viability of the state''s recall mechanism.', 'https://www.coloradosos.gov/pubs/elections/Recall/', 'Colorado Secretary of State - Historical Recall Data', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('1a441d7a3c135bc1', 'CO', '["state"]', 'ballot_access', 'What are the signature and geographic requirements for a citizen initiative in Colorado?', '["How many signatures to put a measure on the Colorado ballot?","Geographic distribution for Colorado initiatives","2% senate district rule Colorado"]', 'For 2026, citizen initiatives require 124,238 valid signatures. Additionally, to ensure statewide support rather than localized backing, proponents must gather signatures equal to at least 2% of the registered voters in each of Colorado''s 35 state senate districts.', 'https://www.coloradosos.gov/pubs/elections/Initiatives/', 'Colorado Secretary of State - Initiatives', '2026-04-21', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('79ce7b476c358f60', 'CO', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass a constitutional amendment in Colorado?', '["Does a constitutional amendment need 55% in Colorado?","Supermajority requirement for CO ballot measures","Initiated statute vs constitutional amendment Colorado"]', 'To pass a citizen-initiated constitutional amendment, a 55% supermajority of the public vote is required. However, citizen-initiated state statutes only require a simple majority (50% + 1) of the vote to pass.', 'https://www.coloradosos.gov/pubs/elections/Initiatives/', 'Colorado Secretary of State - Initiatives', '2026-04-21', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('c8a76b749a18f2ed', 'CO', '["state","federal","county"]', 'runoff_rules', 'Does Colorado use runoff elections for close races?', '["Are there runoffs in Colorado primaries?","How are tied elections decided in Colorado?","Tie-breaker rules Colorado elections"]', 'No, Colorado does not use runoff elections for state or federal offices. If a general or primary election ends in an exact tie after all mandatory recounts are exhausted, the winner is determined by drawing lots (e.g., a coin toss) administered by the Secretary of State or designated election official.', 'https://law.justia.com/codes/colorado/2022/title-1/article-11/part-1/section-1-11-101/', 'CRS 1-11-101', '2026-04-21', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('39d04b2c8b139e64', 'CO', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Colorado?', '["Does Colorado use ranked choice voting?","RCV status in Colorado 2026","SB24-210 ranked choice voting restrictions"]', 'As of 2026, Ranked Choice Voting is used in select local municipal elections (e.g., Boulder, Telluride). Statewide implementation faces hurdles; recent legislation (SB24-210) imposed strict requirements on uniform voting system capabilities before RCV can be broadly expanded for state or federal races.', 'https://www.coloradosos.gov/pubs/elections/FAQs/RCVFAQ.html', 'Colorado Secretary of State - Ranked Choice Voting FAQ', '2026-04-21', 'volatile', 'official_source_direct', 'All candidates', 'batch_2026-05-14T20-23-48_colorado_full_v1'),
  ('2b37503eb286f7e5', 'CO', '["state"]', 'ballot_access', 'What is the process for a citizen-led veto referendum in Colorado?', '["How to refer a CO bill to the ballot","Colorado citizen referendum signature requirement","Veto referendum deadline Colorado"]', 'Under Article V, Section 1 of the Colorado Constitution, citizens may refer any act (or part of an act) passed by the General Assembly to a vote of the people. Proponents must gather signatures equal to 5% of the total votes cast for Secretary of State in the previous election. The petition must be filed within 90 days after the final adjournment of the legislative session that passed the bill.', 'https://law.justia.com/constitution/colorado/cnart5.html', 'Colorado Constitution Article V, Section 1', '2026-05-14', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-14T20-23-48_colorado_full_v1')
